def subarraySum(self, nums: List[int], k: int) -&gt; int:
    n_sub_sum_k = 0
    for i in range(len(nums)):
        sum_sub = 0
        for j in range(i, len(nums)):
            sum_sub += nums[j]
            if sum_sub == k:
                # Even find one, will continue since there may be more
                n_sub_sum_k += 1

    return n_sub_sum_k
